def hebrew_date():
    return DATE_HEBREW


def article_card_html(article):
    aid = f"{DATE_ISO}-{article['id']}"
    return f"""<div class="news-card" data-article-id="{aid}" data-category="{article['category']}">
    <div class="card-content">
        <span class="card-category">{article['category_label']}</span>
        <h3 class="card-title">{article['title']}</h3>
        <p class="card-summary">{article['summary']}</p>
        <div class="card-footer">
            <a href="articles/{aid}.html" class="read-more">קרא עוד ←</a>
            <div class="rating-buttons">
                <button class="rating-btn" data-article-id="{aid}" data-rating="up">👍</button>
                <button class="rating-btn" data-article-id="{aid}" data-rating="down">👎</button>
            </div>
        </div>
    </div>
</div>
"""


def article_page_html(article, template):
    aid = f"{DATE_ISO}-{article['id']}"
    body = article["body"]
    out = template
    out = out.replace("{{ARTICLE_TITLE}}", article["title"])
    out = out.replace("{{ARTICLE_CATEGORY}}", article["category_label"])
    out = out.replace("{{ARTICLE_DATE}}", DATE_HEBREW)
    # Remove the image block since we don't fetch og images
    out = re.sub(
        r"\{\{#ARTICLE_IMAGE\}\}[\s\S]*?\{\{/ARTICLE_IMAGE\}\}", "", out
    )
    out = out.replace("{{ARTICLE_BODY}}", body)
    out = out.replace("{{ARTICLE_ID}}", aid)
    out = out.replace("{{SOURCE_URL}}", article["source"])
    return out


def build_calendar_html():
    events = [
        ("כל היום", "🕯️ חג השבועות (יום טוב)"),
        ("כל היום", "🚀 Challenge EN - Round 4 (יום אחרון)"),
        ("כל היום", "🏊 הילדים בחופש - והבריכה פתוחה"),
        ("18:00", "🎤 הרצאה בטופ דוג סאמיט (וירטואלי, Zoom)"),
    ]
    html = ""
    for time_str, title in events:
        html += f'<div class="calendar-event"><span class="event-time">{time_str}</span><span class="event-title">{title}</span></div>\n'
    return html


def section_cards(category):
    items = [a for a in ARTICLES if a["category"] == category]
    return "".join(article_card_html(a) for a in items)


